import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [complaints, setComplaints] = useState([]);

  // Backend se complaints fetch karne ke liye
  useEffect(() => {
    axios.get('http://127.0.0.1:8000/api/complaints/')
      .then(res => setComplaints(res.data))
      .catch(err => console.log("Backend not connected yet", err));
  }, []);

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial' }}>
      <h1 style={{ color: '#2c3e50' }}>Digital Grievance Redressal System</h1>
      <hr />
      
      <h3>Registered Complaints:</h3>
      {complaints.length === 0 ? <p>No complaints found (Check if Backend is running).</p> : (
        <ul>
          {complaints.map(c => (
            <li key={c.id}><b>{c.title}</b> - Status: {c.status}</li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default App;
